patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 6cff3c7af91e..f80a0c90d40e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -504,11 +504,25 @@ static Instruction *foldCttzCtlz(IntrinsicInst &II, InstCombinerImpl &IC) {
   }

   // If ctlz/cttz is only used as a shift amount, set is_zero_poison to true.
+
+  
   if (II.hasOneUse() && match(Op1, m_Zero()) &&
       match(II.user_back(), m_Shift(m_Value(), m_Specific(&II))))
-    return IC.replaceOperand(II, 1, IC.Builder.getTrue());
-
-  Constant *C;
+{
+  // Create a new call with is_zero_poison=true.
+  auto *NewCall = IC.Builder.CreateBinaryIntrinsic(II.getIntrinsicID(), Op0, IC.Builder.getTrue());
+  if (auto *NewCI = dyn_cast<CallInst>(NewCall)) {
+    // Preserve attributes from the old call.
+    NewCI->setAttributes(II.getAttributes());
+    // If return has noundef, but operand may be zero, drop noundef to avoid UB for x==0.
+    if (NewCI->hasRetAttr(Attribute::NoUndef)) {
+      auto SQ = IC.getSimplifyQuery().getWithInstruction(&II);
+      if (!isKnownNonZero(Op0, SQ))
+        NewCI->removeRetAttr(Attribute::NoUndef);
+    }
+  }
+  return IC.replaceInstUsesWith(II, NewCall);
+}Constant *C;

   if (IsTZ) {
     // cttz(-x) -> cttz(x)

